#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, N; scanf("%lld %lld", &X, &N);
        long long ans = X * (2 * N + 1 - X) - 2 * N;
        printf("%lld\n", ans);
    }
    return 0;
}

